      out.write("            </div>\n");
      out.write("            <div id=\"trade-status\"></div>\n");
      out.write("        </div>\n");
      out.write("\n");
      out.write("        <div class=\"card portfolio-card\">\n");
      out.write("            <div class=\"card-title\">My Portfolio (All Holdings)</div>\n");
      out.write("            <div class=\"pnl-label\">Total Unrealized P&amp;L</div>\n");
      out.write("            <div class=\"pnl-big\" id=\"pnl-display\">$0.00</div>\n");
      out.write("            \n");
      out.write("            <div class=\"tbl-scroll\" style=\"margin-top: 15px; border-top: 1px solid var(--border); padding-top: 10px; max-height: 200px;\">\n");
      out.write("                <table style=\"width: 100%; text-align: left; font-size: 0.85rem;\">\n");
      out.write("                    <thead>\n");
      out.write("                        <tr>\n");
      out.write("                            <th style=\"padding-bottom: 8px; color: var(--muted);\">Asset</th>\n");
      out.write("                            <th style=\"padding-bottom: 8px; color: var(--muted);\">Qty</th>\n");
      out.write("                            <th style=\"padding-bottom: 8px; color: var(--muted);\">Avg Price</th>\n");
      out.write("                            <th style=\"padding-bottom: 8px; color: var(--muted); text-align: right;\">P&amp;L</th>\n");
      out.write("                        </tr>\n");
      out.write("                    </thead>\n");
      out.write("                    <tbody id=\"portfolio-positions\">\n");
      out.write("                        <tr><td colspan=\"4\" style=\"text-align:center;color:var(--muted);padding:20px;\">No open positions</td></tr>\n");
      out.write("                    </tbody>\n");
      out.write("                </table>\n");
      out.write("            </div>\n");
      out.write("        </div>\n");
      out.write("\n");
      out.write("        <div class=\"card chart-card\">\n");
      out.write("            <div class=\"card-title\" style=\"margin-bottom:10px;\">Price History</div>\n");
      out.write("            <div class=\"chart-wrap\"><canvas id=\"priceChart\"></canvas></div>\n");
      out.write("        </div>\n");
      out.write("\n");
      out.write("        <div class=\"card orders-card\">\n");
      out.write("            <div class=\"card-title\">My Open Orders</div>\n");
      out.write("            <div id=\"orders-list\"><div class=\"empty-msg\">No pending orders</div></div>\n");
      out.write("        </div>\n");
      out.write("\n");
      out.write("        <div class=\"card history-card\">\n");
      out.write("            <div class=\"history-header\">\n");
      out.write("                <div class=\"card-title\" style=\"margin-bottom:0;\">Market Trade History</div>\n");
      out.write("                <span class=\"badge\" id=\"trade-count-badge\">0 trades</span>\n");
      out.write("            </div>\n");
      out.write("            <div class=\"history-stats\">\n");
      out.write("                <div class=\"h-stat\">\n");
      out.write("                    <div class=\"h-stat-label\">Total Trades</div>\n");
      out.write("                    <div class=\"h-stat-value\" id=\"hist-count\">0</div>\n");
      out.write("                </div>\n");
      out.write("                <div class=\"h-stat\">\n");
      out.write("                    <div class=\"h-stat-label\">Total Volume</div>\n");
      out.write("                    <div class=\"h-stat-value\" id=\"hist-volume\">0 shares</div>\n");
      out.write("                </div>\n");
      out.write("                <div class=\"h-stat\">\n");
      out.write("                    <div class=\"h-stat-label\">VWAP</div>\n");
      out.write("                    <div class=\"h-stat-value\" id=\"hist-vwap-bottom\" style=\"color:var(--blue)\">$0.00</div>\n");
      out.write("                </div>\n");
      out.write("            </div>\n");
      out.write("            <div class=\"tbl-scroll\">\n");
      out.write("                <table>\n");
      out.write("                    <thead>\n");
      out.write("                        <tr>\n");
      out.write("                            <th>#</th>\n");
      out.write("                            <th>Symbol</th>\n");
      out.write("                            <th>Qty</th>\n");
      out.write("                            <th>Price</th>\n");
      out.write("                            <th>Buyer</th>\n");
      out.write("                            <th>Seller</th>\n");
      out.write("                            <th>Time</th>\n");
      out.write("                        </tr>\n");
      out.write("                    </thead>\n");
      out.write("                    <tbody id=\"trade-table-body\">\n");
      out.write("                        <tr><td colspan=\"7\" style=\"text-align:center;color:var(--muted);padding:20px;\">Waiting for trades...</td></tr>\n");
      out.write("                    </tbody>\n");
      out.write("                </table>\n");
      out.write("            </div>\n");
      out.write("        </div>\n");
      out.write("\n");
      out.write("    </div></div><script>\n");
      out.write("// ---\n");
      out.write("//  Global State\n");
      out.write("// ---\n");
      out.write("let currentSymbol = 'AAPL'; // Default active stock\n");
      out.write("let lastPrice = null;\n");
      out.write("let chartColor = '#3fb950';\n");
      out.write("let pollIntervals = [];\n");
      out.write("\n");
      out.write("// ---\n");
      out.write("//  Landing Page Logic\n");
      out.write("// ---\n");
      out.write("function enterMarket() {\n");
      out.write("    const landing = document.getElementById('landing-screen');\n");
      out.write("    landing.style.transform = 'scale(1.1)';\n");
      out.write("    landing.style.opacity = '0';\n");
      out.write("    \n");
      out.write("    setTimeout(() => {\n");
      out.write("        landing.style.display = 'none';\n");
      out.write("        document.getElementById('dashboard-screen').style.display = 'block';\n");
      out.write("        startPolling();\n");
      out.write("    }, 600);\n");
      out.write("}\n");
      out.write("\n");
      out.write("// ---\n");
      out.write("//  Stock Selector Logic\n");
      out.write("// ---\n");
      out.write("function changeStock() {\n");
      out.write("    currentSymbol = document.getElementById('stockSelector').value;\n");
      out.write("    document.getElementById('ticker-display-name').textContent = currentSymbol + ' (SIMULATED)';\n");
      out.write("    \n");
      out.write("    // Reset local data\n");
      out.write("    lastPrice = null; \n");
      out.write("    document.getElementById('price-change').textContent = 'Fetching...';\n");
      out.write("    document.getElementById('price-change').style.color = 'var(--muted)';\n");
      out.write("    \n");
      out.write("    // Reset Chart\n");
      out.write("    priceChart.data.labels = [];\n");
      out.write("    priceChart.data.datasets[0].data = [];\n");
      out.write("    priceChart.data.datasets[0].label = currentSymbol;\n");
      out.write("    priceChart.update();\n");
      out.write("\n");
      out.write("    // Clear Trade History UI temporarily\n");
      out.write("    document.getElementById('trade-table-body').innerHTML = '<tr><td colspan=\"7\" style=\"text-align:center;color:var(--muted);padding:20px;\">Fetching ' + currentSymbol + ' trades...</td></tr>';\n");
      out.write("\n");
      out.write("    pollAll(); \n");
      out.write("}\n");
      out.write("\n");
      out.write("// ---\n");
      out.write("//  Chart Setup\n");
      out.write("// ---\n");
      out.write("const ctx = document.getElementById('priceChart').getContext('2d');\n");
      out.write("const priceChart = new Chart(ctx, {\n");
      out.write("    type: 'line',\n");
      out.write("    data: {\n");
      out.write("        labels: [],\n");
      out.write("        datasets: [{\n");
      out.write("            label: currentSymbol,\n");
      out.write("            data: [],\n");
      out.write("            borderColor: '#3fb950',\n");
      out.write("            backgroundColor: 'rgba(63,185,80,0.08)',\n");
      out.write("            borderWidth: 1.5,\n");
      out.write("            pointRadius: 0,\n");
      out.write("            fill: true,\n");
      out.write("            tension: 0.3\n");
      out.write("        }]\n");
      out.write("    },\n");
      out.write("    options: {\n");
      out.write("        responsive: true,\n");
      out.write("        maintainAspectRatio: false,\n");
      out.write("        animation: { duration: 300 },\n");
      out.write("        interaction: { mode: 'index', intersect: false },\n");
      out.write("        scales: {\n");
      out.write("            x: { display: false },\n");
      out.write("            y: { grid: { color: '#21262d' }, ticks: { color: '#8b949e', callback: v => '$' + v.toFixed(2) } }\n");
      out.write("        },\n");
      out.write("        plugins: {\n");
      out.write("            legend: { display: false },\n");
      out.write("            tooltip: {\n");
      out.write("                backgroundColor: '#161b22', borderColor: '#30363d', borderWidth: 1,\n");
      out.write("                titleColor: '#8b949e', bodyColor: '#c9d1d9',\n");
      out.write("                callbacks: { label: ctx => ' $' + ctx.parsed.y.toFixed(2) }\n");
      out.write("            }\n");
      out.write("        }\n");
      out.write("    }\n");
      out.write("});\n");
      out.write("\n");
      out.write("function setChartColor(color) {\n");
      out.write("    if (chartColor === color) return;\n");
      out.write("    chartColor = color;\n");
      out.write("    priceChart.data.datasets[0].borderColor = color;\n");
      out.write("    priceChart.data.datasets[0].backgroundColor = color === '#3fb950' ? 'rgba(63,185,80,0.08)' : 'rgba(248,81,73,0.08)';\n");
      out.write("}\n");
      out.write("\n");
      out.write("// ---\n");
      out.write("//  Polling Functions\n");
      out.write("// ---\n");
      out.write("function pollPrice() {\n");
      out.write("    fetch('PriceServlet?symbol=' + currentSymbol)\n");
      out.write("        .then(r => r.text())\n");
      out.write("        .then(txt => {\n");
      out.write("            const p = parseFloat(txt);\n");
      out.write("            if(isNaN(p)) return;\n");
      out.write("\n");
      out.write("            const el = document.getElementById('price-display');\n");
      out.write("            const chEl = document.getElementById('price-change');\n");
      out.write("\n");
      out.write("            if (lastPrice !== null) {\n");
      out.write("                const diff = p - lastPrice;\n");
      out.write("                const pct  = lastPrice !== 0 ? (diff / lastPrice * 100) : 0;\n");
      out.write("                if (diff > 0) {\n");
      out.write("                    el.className = 'price-up';\n");
      out.write("                    chEl.style.color = 'var(--green)';\n");
      out.write("                    chEl.textContent = '+$' + diff.toFixed(2) + ' (+' + pct.toFixed(2) + '%)';\n");
      out.write("                    setChartColor('#3fb950');\n");
      out.write("                } else if (diff < 0) {\n");
      out.write("                    el.className = 'price-down';\n");
      out.write("                    chEl.style.color = 'var(--red)';\n");
      out.write("                    chEl.textContent = '-$' + Math.abs(diff).toFixed(2) + ' (' + pct.toFixed(2) + '%)';\n");
      out.write("                    setChartColor('#f85149');\n");
      out.write("                } else {\n");
      out.write("                    el.className = 'price-flat';\n");
      out.write("                }\n");
      out.write("            } else {\n");
      out.write("                chEl.textContent = 'Market open';\n");
      out.write("                chEl.style.color = 'var(--muted)';\n");
      out.write("            }\n");
      out.write("\n");
      out.write("            el.textContent = '$' + p.toFixed(2);\n");
      out.write("            lastPrice = p;\n");
      out.write("        })\n");
      out.write("        .catch(() => {});\n");
      out.write("}\n");
      out.write("\n");
      out.write("function pollPriceHistory() {\n");
      out.write("    fetch('PriceHistoryServlet?symbol=' + currentSymbol + '&limit=120')\n");
      out.write("        .then(r => r.json())\n");
      out.write("        .then(data => {\n");
      out.write("            if(!data.history) return;\n");
      out.write("            const labels = data.history.map(p => new Date(p.time.replace(' ', 'T')).toLocaleTimeString());\n");
      out.write("            const prices = data.history.map(p => p.price);\n");
      out.write("\n");
      out.write("            priceChart.data.labels  = labels;\n");
      out.write("            priceChart.data.datasets[0].data = prices;\n");
      out.write("            priceChart.update('none');\n");
      out.write("\n");
      out.write("            if (data.dayHigh > 0) {\n");
      out.write("                document.getElementById('stat-high').textContent = '$' + data.dayHigh.toFixed(2);\n");
      out.write("                document.getElementById('stat-low').textContent  = '$' + data.dayLow.toFixed(2);\n");
      out.write("            }\n");
      out.write("        })\n");
      out.write("        .catch(() => {});\n");
      out.write("}\n");
      out.write("\n");
      out.write("function pollPortfolio() {\n");
      out.write("    fetch('PortfolioServlet')\n");
      out.write("        .then(r => r.json())\n");
      out.write("        .then(d => {\n");
      out.write("            const pnlEl = document.getElementById('pnl-display');\n");
      out.write("            const totalPnl = d.totalPnl || 0;\n");
      out.write("            pnlEl.textContent = (totalPnl >= 0 ? '+$' : '-$') + Math.abs(totalPnl).toFixed(2);\n");
      out.write("            pnlEl.style.color = totalPnl > 0 ? 'var(--green)' : totalPnl < 0 ? 'var(--red)' : 'var(--text)';\n");
      out.write("\n");
      out.write("            const tbody = document.getElementById('portfolio-positions');\n");
      out.write("            const positions = d.positions || [];\n");
      out.write("            \n");
      out.write("            if (positions.length === 0) {\n");
      out.write("                tbody.innerHTML = '<tr><td colspan=\"4\" style=\"text-align:center;color:var(--muted);padding:20px;\">No open positions</td></tr>';\n");
      out.write("                return;\n");
      out.write("            }\n");
      out.write("\n");
      out.write("            tbody.innerHTML = positions.map(pos => {\n");
      out.write("                const pnlColor = pos.unrealizedPnl > 0 ? 'var(--green)' : pos.unrealizedPnl < 0 ? 'var(--red)' : 'var(--text)';\n");
      out.write("                const pnlSign = pos.unrealizedPnl > 0 ? '+' : '';\n");
      out.write("                return `\n");
      out.write("                    <tr>\n");
      out.write("                        <td style=\"font-weight: 700; color: var(--blue); padding-bottom: 6px;\">${pos.symbol}</td>\n");
      out.write("                        <td style=\"padding-bottom: 6px;\">${pos.shares}</td>\n");
      out.write("                        <td style=\"font-variant-numeric:tabular-nums; padding-bottom: 6px;\">$${pos.avgPrice.toFixed(2)}</td>\n");
      out.write("                        <td style=\"text-align: right; color: ${pnlColor}; font-weight: 600; font-variant-numeric:tabular-nums; padding-bottom: 6px;\">\n");
      out.write("                            ${pnlSign}$${pos.unrealizedPnl.toFixed(2)}\n");
      out.write("                        </td>\n");
      out.write("                    </tr>\n");
      out.write("                `;\n");
      out.write("            }).join('');\n");
      out.write("        })\n");
      out.write("        .catch(() => {});\n");
      out.write("}\n");
      out.write("\n");
      out.write("function pollOpenOrders() {\n");
      out.write("    // Correctly fetching open orders specifically for the selected symbol\n");
      out.write("    fetch('OpenOrdersServlet?symbol=' + currentSymbol)\n");
      out.write("        .then(r => r.text())\n");
      out.write("        .then(text => {\n");
      out.write("            const el = document.getElementById('orders-list');\n");
      out.write("            let orders;\n");
      out.write("            try { orders = JSON.parse(text); } catch(e) { return; }\n");
      out.write("            \n");
      out.write("            if (!Array.isArray(orders) || orders.length === 0) {\n");
      out.write("                el.innerHTML = '<div class=\"empty-msg\">No pending orders</div>';\n");
      out.write("                return;\n");
      out.write("            }\n");
      out.write("            \n");
      out.write("            const valid = orders.filter(o => o && o.type && o.symbol === currentSymbol);\n");
      out.write("            if (valid.length === 0) {\n");
      out.write("                el.innerHTML = '<div class=\"empty-msg\">No pending orders for ' + currentSymbol + '</div>';\n");
      out.write("                return;\n");
      out.write("            }\n");
      out.write("            \n");
      out.write("            el.innerHTML = valid.map(o => {\n");
      out.write("                const color = o.type === 'BUY' ? 'var(--green)' : 'var(--red)';\n");
      out.write("                const price = parseFloat(o.price).toFixed(2);\n");
      out.write("                return `<div class=\"order-row\">\n");
      out.write("                    <span class=\"order-type\" style=\"color:${color}\">${o.type}</span>\n");
      out.write("                    <span class=\"order-qty\">${o.qty} shares</span>\n");
      out.write("                    <span class=\"order-price\">$${price}</span>\n");
      out.write("                </div>`;\n");
      out.write("            }).join('');\n");
      out.write("        })\n");
      out.write("        .catch(() => {});\n");
      out.write("}\n");
      out.write("\n");
      out.write("function pollTradeHistory() {\n");
      out.write("    fetch('TradeHistoryServlet?symbol=' + currentSymbol + '&limit=25')\n");
      out.write("        .then(r => r.text())\n");
      out.write("        .then(text => {\n");
      out.write("            let data;\n");
      out.write("            try { data = JSON.parse(text); } catch(e) { return; }\n");
      out.write("\n");
      out.write("            const count  = data.totalCount  || 0;\n");
      out.write("            const volume = data.totalVolume || 0;\n");
      out.write("            const vwap   = parseFloat(data.vwap) || 0;\n");
      out.write("\n");
      out.write("            document.getElementById('hist-count').textContent        = count.toLocaleString();\n");
      out.write("            document.getElementById('hist-volume').textContent       = volume.toLocaleString() + ' shares';\n");
      out.write("            document.getElementById('hist-vwap-bottom').textContent  = '$' + vwap.toFixed(2);\n");
      out.write("            document.getElementById('stat-vwap').textContent         = '$' + vwap.toFixed(2);\n");
      out.write("            document.getElementById('trade-count-badge').textContent = count + ' trades';\n");
      out.write("\n");
      out.write("            const trades = data.trades || [];\n");
      out.write("            if (trades.length === 0) {\n");
      out.write("                document.getElementById('trade-table-body').innerHTML = '<tr><td colspan=\"7\" style=\"text-align:center;color:var(--muted);padding:20px;\">No trades yet for ' + currentSymbol + '...</td></tr>';\n");
      out.write("                return;\n");
      out.write("            }\n");
      out.write("\n");
      out.write("            const rows = trades.map(t => {\n");
      out.write("                if (!t || t.id === undefined) return '';\n");
      out.write("                const isHuman = t.buyer === 'Human Player' || t.seller === 'Human Player';\n");
      out.write("                const rowClass = isHuman ? 'human-row' : '';\n");
      out.write("                const timeStr = t.time ? t.time.substring(11, 19) : '--';\n");
      out.write("                const price = parseFloat(t.price) || 0;\n");
      out.write("                const buyerStyle = t.buyer === 'Human Player' ? 'color:var(--blue);font-weight:700' : '';\n");
      out.write("                const sellerStyle = t.seller === 'Human Player' ? 'color:var(--blue);font-weight:700' : '';\n");
      out.write("\n");
      out.write("                return `<tr class=\"${rowClass}\">\n");
      out.write("                    <td style=\"color:var(--muted)\">#${t.id}</td>\n");
      out.write("                    <td>${t.symbol || ''}</td>\n");
      out.write("                    <td>${t.quantity || ''}</td>\n");
      out.write("                    <td style=\"font-variant-numeric:tabular-nums\">$${price.toFixed(2)}</td>\n");
      out.write("                    <td style=\"${buyerStyle}\">${t.buyer || ''}</td>\n");
      out.write("                    <td style=\"${sellerStyle}\">${t.seller || ''}</td>\n");
      out.write("                    <td style=\"color:var(--muted)\">${timeStr}</td>\n");
      out.write("                </tr>`;\n");
      out.write("            }).join('');\n");
      out.write("\n");
      out.write("            document.getElementById('trade-table-body').innerHTML = rows;\n");
      out.write("        })\n");
      out.write("        .catch(() => {});\n");
      out.write("}\n");
      out.write("\n");
      out.write("// ---\n");
      out.write("//  Submit Trade\n");
      out.write("// ---\n");
      out.write("function submitTrade(action) {\n");
      out.write("    const qty   = parseFloat(document.getElementById('trade-qty').value);\n");
      out.write("    const price = parseFloat(document.getElementById('trade-price').value);\n");
      out.write("    const st    = document.getElementById('trade-status');\n");
      out.write("\n");
      out.write("    if (isNaN(qty) || isNaN(price) || qty <= 0 || price <= 0) {\n");
      out.write("        st.textContent = '⚠ Enter a valid quantity and price.';\n");
      out.write("        st.className = 'status-fail';\n");
      out.write("        return;\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    const params = new URLSearchParams();\n");
      out.write("    params.append('symbol', currentSymbol);\n");
      out.write("    params.append('action', action);\n");
      out.write("    params.append('quantity', Math.floor(qty).toString());\n");
      out.write("    params.append('price', price.toFixed(2));\n");
      out.write("\n");
      out.write("    fetch('TradeServlet', {\n");
      out.write("        method: 'POST',\n");
      out.write("        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },\n");
      out.write("        body: params.toString()\n");
      out.write("    })\n");
      out.write("    .then(r => r.text().then(msg => ({ ok: r.ok, msg })))\n");
      out.write("    .then(({ ok, msg }) => {\n");
      out.write("        st.innerHTML = ok ? '&#10003; ' + msg : '&#10007; ' + msg;\n");
      out.write("        st.className = ok ? 'status-ok' : 'status-fail';\n");
      out.write("        if (ok) {\n");
      out.write("            document.getElementById('trade-qty').value   = '';\n");
      out.write("            document.getElementById('trade-price').value = '';\n");
      out.write("            \n");
      out.write("            // Force an immediate update of open orders to feel more responsive\n");
      out.write("            pollOpenOrders();\n");
      out.write("        }\n");
      out.write("    })\n");
      out.write("    .catch(() => {\n");
      out.write("        st.textContent = '❌ Network error.';\n");
      out.write("        st.className = 'status-fail';\n");
      out.write("    });\n");
      out.write("}\n");
      out.write("\n");
      out.write("// ---\n");
      out.write("//  Startup Polling Controller\n");
      out.write("// ---\n");
      out.write("function pollAll() {\n");
      out.write("    pollPrice();\n");
      out.write("    pollPriceHistory();\n");
      out.write("    pollPortfolio();\n");
      out.write("    pollOpenOrders();\n");
      out.write("    pollTradeHistory();\n");
      out.write("}\n");
      out.write("\n");
      out.write("function startPolling() {\n");
      out.write("    pollAll(); \n");
      out.write("    pollIntervals.push(setInterval(pollPrice, 1000));\n");
      out.write("    pollIntervals.push(setInterval(pollPriceHistory, 5000));\n");
      out.write("    pollIntervals.push(setInterval(pollPortfolio, 1500));\n");
      out.write("    pollIntervals.push(setInterval(pollOpenOrders, 1500));\n");
      out.write("    pollIntervals.push(setInterval(pollTradeHistory, 3000));\n");
      out.write("}\n");
      out.write("</script>\n");
      out.write("</body>\n");
      out.write("</html>");
